// Format RSS data for the Sunidhi website
const items = $input.all();

// Sort by date (newest first)
const sortedItems = items.sort((a, b) => {
  const dateA = new Date(a.json.pubDate || a.json.isoDate || 0);
  const dateB = new Date(b.json.pubDate || b.json.isoDate || 0);
  return dateB - dateA;
});

// Take only the latest 20 articles
const latestArticles = sortedItems.slice(0, 20);

// Format articles for the website
const articles = latestArticles.map(item => {
  const json = item.json;

  return {
    title: json.title || 'Untitled',
    description: json.description || json.contentSnippet || json.summary || '',
    link: json.link || json.url || '',
    pubDate: json.pubDate || json.isoDate || new Date().toISOString(),
    source: json.creator || json['dc:creator'] || extractSource(json.link) || 'Unknown',
    author: json.author || json['dc:creator'] || ''
  };
});

// Helper function to extract source from URL
function extractSource(url) {
  if (!url) return 'Unknown';
  try {
    const hostname = new URL(url).hostname;
    if (hostname.includes('economictimes')) return 'Economic Times';
    if (hostname.includes('moneycontrol')) return 'MoneyControl';
    if (hostname.includes('business-standard')) return 'Business Standard';
    return hostname.replace('www.', '').split('.')[0];
  } catch {
    return 'Unknown';
  }
}

// Return in the format expected by the website
return [{ json: { articles } }];
